group_id, service_provider_id, service_provider_name, state, remark, created_by, created_name, created_date, modified_by,
modified_name, modified_date, version, deleted_flag from base_platform_store ps
where ps.deleted_flag = 0
     and ps.group_id = #{groupId}
     and ps.service_provider_id = #{serviceProviderId}

        and ps.service_provider_id in

            #{item}


     and ps.config_code = #{configCode}
     and ps.config_name like concat('%', #{configName}, '%')
     and ps.platform_code = #{platformCode}

        and ps.platform_code in

            #{item}


     and ps.platform_name like concat('%', #{platformName}, '%')
     and ps.auth_store_code like concat('%', concat(#{authStoreCodeLike}, '%'))
     and ps.auth_store_name like concat('%', concat(#{authStoreNameLike}, '%'))
     and ps.state = #{state}
     and ps.belong_owner_id = #{belongOwnerId}

        and ps.belong_owner_id in

            #{item}


     and ps.id = #{id}

        and ps.id in

            #{item}


order by ps.created_date desc

mapper.update:
update base_platform_store
config_code = #{configCode}, config_name = #{configName}, platform_code = #{platformCode}, platform_name = #{platformName}, auth_store_code = #{authStoreCode}, auth_store_name = #{authStoreName}, service_provider_id = #{serviceProviderId}, service_provider_name = #{serviceProviderName}, belong_owner_id = #{belongOwnerId}, belong_owner_name = #{belongOwnerName}, state = #{state}, remark = #{remark},
modified_by = #{modifiedBy}, modified_name = #{modifiedName}, modified_date = #{modifiedDate}, version = version + 1,, deleted_flag = #{deletedFlag},
where id = #{id}
and version = #{version}
